class Solution:
    def maxMeetings(self, intervals: list[list[int]]) -> int:
        intervals.sort(key=lambda x: x[1])
        end_time = -1
        count = 0
        for start, end in intervals:
            if start >= end_time:
                count += 1
                end_time = end
        return count

